if (tx.content.custom_charges?.ipfs) {
    const { max_cost_dem, file_size_bytes, operation } = tx.content.custom_charges.ipfs
    const isGenesis = await isGenesisAccount(tx.content.from)
    const usedFreeBytes = await getUsedFreeBytes(tx.content.from)

