Add DTR relay logic to endpointHandlers.ts after transaction validation.

## File to modify

`src/libs/network/endpointHandlers.ts`

## Reference

`git diff testnet...origin/dtr -- src/libs/network/endpointHandlers.ts`

## Integration Point

After validation succeeds, before adding to mempool:

```typescript
import isValidatorForNextBlock from "src/libs/consensus/v2/routines/isValidator"
import { DTRManager } from "./dtr/dtrmanager"

// After validation passes...

// DTR: Check if we should relay instead of storing locally (Production only)
if (getSharedState.PROD) {
    const { isValidator, validators } = await isValidatorForNextBlock()

    if (!isValidator) {
        // Relay to all validators in random order for load balancing
        const shuffledValidators = validators.sort(() => Math.random() - 0.5)

        const results = await Promise.allSettled(
            shuffledValidators.map(validator =>
                DTRManager.relayTransactions(validator, [validatedData])
            )
        )

        // Cache failed relays for background retry
        for (const result of results) {
            if (result.status === "fulfilled" && result.value.result !== 200) {
                DTRManager.validityDataCache.set(result.value.extra.peer, validatedData)
            }
        }

        return { success: true, response: { message: "Transaction relayed to validators" } }
    }

    // If in consensus loop, cache for post-block relay
    if (getSharedState.inConsensusLoop) {
        DTRManager.validityDataCache.set(queriedTx.hash, validatedData)
        if (!DTRManager.isWaitingForBlock) {
            DTRManager.waitForBlockThenRelay()
        }
        return { success: true, response: { message: "Transaction queued for relay" } }
    }
}

// Fallback: add to local mempool (validator or non-PROD)
```

## Key Points

* Only applies when PROD=true
* Non-validators relay to all validators
* Random ordering for load balancing
* Fallback to local mempool if all relays fail
* During consensus loop, cache and relay after block

